INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Corporate Cards$q$, $q$Unlimited physical and virtual cards with configurable spend limits and controls, issued with no annual fee or interest on the free plan.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Expense Management$q$, $q$Automatic receipt capture and matching through SMS, email, Slack, or the mobile app, cutting down on manual expense reports.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Accounts Payable & Bill Pay$q$, $q$OCR-based invoice processing, configurable approval workflows, and scheduled vendor payments to automate accounts payable.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Accounting Automation$q$, $q$Auto-coded transactions that sync to connected accounting and ERP systems such as QuickBooks, Xero, Sage Intacct, and NetSuite.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Procurement$q$, $q$Purchase-request workflows and vendor management tools available as an add-on for teams on paid plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Business Travel$q$, $q$Integrated flight and hotel booking tied to company spend policy, with trip-level expense tracking.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Ramp Treasury$q$, $q$Business cash management for holding and moving funds alongside card and payables activity.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Real-Time Reporting & Budgets$q$, $q$Dashboards for cross-department spend visibility, budget tracking, and finance reporting.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Ramp Intelligence (AI)$q$, $q$AI-driven policy checks, anomaly detection, and auto-classification aimed at reducing manual review work.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Custom Approval Workflows & Roles$q$, $q$Configurable multi-level approval chains and role-based permissions for admins, managers, and employees.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Free core plan covers unlimited corporate cards and expense management with no monthly fee$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Deep automation around receipt matching and expense coding reduces manual finance work$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$All-in-one suite covering cards, AP, procurement, travel, and accounting reduces the need for separate tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Strong integrations with mainstream accounting and ERP systems like QuickBooks, Xero, Sage Intacct, and NetSuite$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Modern, well-regarded web dashboard and mobile app for both admins and employees$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Advanced automation, procurement, and premium integrations require upgrading to the paid Plus or Enterprise plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Card underwriting and limits depend on business financial history, which can be restrictive for pre-revenue companies$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$International coverage for local-currency cards and multi-entity support is more limited than some global competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$No dedicated invoicing or accounts receivable functionality, since the platform is focused on spend and payables$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$A foreign transaction fee applies to card purchases made outside the free plan's supported currency terms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Is Ramp free to use?$q$, $q$Ramp offers a free plan that includes unlimited corporate cards and core expense management with no monthly fee; the company earns revenue primarily from card interchange rather than charging for the base plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$What is included in Ramp's free plan?$q$, $q$The free plan includes unlimited virtual and physical corporate cards, expense management with receipt matching, basic accounts payable, treasury features, and fundamental accounting automation.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Does Ramp integrate with accounting software?$q$, $q$Yes, Ramp integrates with accounting and ERP platforms including QuickBooks, Xero, Sage Intacct, and NetSuite, with some deeper integrations available on paid plans.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Is there a Ramp mobile app?$q$, $q$Yes, Ramp has a mobile app for iOS and Android that supports card payments, receipt submission, mileage tracking, approvals, and travel booking.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$How does Ramp make money if the card is free?$q$, $q$Ramp generates revenue mainly from interchange fees on card transactions, supplemented by subscription revenue from its paid Plus and Enterprise plans and certain add-ons.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Startup card and expense management$q$, $q$Early-stage companies issue employee cards, set spend limits, and automate receipt collection without adopting a paid expense tool.$q$, $q$Startup founders and finance leads$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Accounts payable automation$q$, $q$Mid-market finance teams use OCR-based invoice capture and approval workflows to process vendor bills and payments faster.$q$, $q$Controllers and AP teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Cross-department budget control$q$, $q$Organizations with multiple teams track real-time spend against budgets and enforce role-based approval policies.$q$, $q$Finance and operations leaders$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Policy-compliant business travel$q$, $q$Companies book flights and hotels through Ramp Travel so bookings automatically follow spend policy and sync to expense records.$q$, $q$Travel-heavy sales and operations teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, $q$["Unlimited virtual and physical corporate cards","Expense management via SMS, email, or Slack","Basic accounts payable with OCR","Treasury features","Fundamental accounting automation","Vendor management tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Plus$q$, $q$$15/user/month plus a platform fee$q$, $q$Monthly (discount available with annual commitment)$q$, $q$["All Free plan features","AI-powered expense reviews","Auto-coded line items","Advanced approval recommendations","Procurement add-on capability","Expanded integrations including NetSuite and Sage Intacct","Real-time budget tracking","Custom user roles and priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual$q$, $q$["All Plus plan features","Premium ERP integrations such as Workday and Oracle","Local currency card issuing across 30+ countries","White-glove support with dedicated account managers","Custom implementation services","Enterprise-grade configuration options"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Ramp is a financial technology company founded in 2019 and headquartered in New York City. The company built its business around a corporate charge card that carries no annual fee, no interest, and no card-replacement fees for customers on its free plan, monetizing primarily through interchange revenue rather than subscription fees. Over time Ramp expanded from a single card product into a broader spend management suite.$q$, $q$Today the platform bundles corporate cards, expense management, accounts payable and bill pay, procurement, business travel booking, and accounting automation into one system. Finance teams can issue unlimited virtual and physical cards with built-in spend controls, automatically match receipts submitted by SMS, email, Slack, or the mobile app, and sync coded transactions to accounting and ERP systems such as QuickBooks, Xero, Sage Intacct, and NetSuite.$q$, $q$Ramp offers a genuinely free tier alongside paid Plus and Enterprise plans that unlock deeper automation, additional integrations, and premium support. This freemium structure lets very small teams run their entire card and expense workflow at no monthly cost, while growing organizations can pay for more advanced approval logic, budgeting, and ERP connectivity as their needs mature.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$who-ramp-is-for$q$, $q$Who Ramp Is For$q$, 2, ARRAY[$q$Ramp is built for finance and operations teams at startups and small-to-midsize businesses that want to consolidate multiple point tools for cards, expenses, and payables into a single dashboard. Companies that are actively trying to cut manual bookkeeping work, close their books faster, and reduce time spent chasing receipts tend to be a strong fit, since much of the platform's value comes from automating those repetitive tasks.$q$, $q$It also suits organizations that already use, or plan to adopt, mainstream accounting or ERP software, since Ramp's integrations with tools like QuickBooks, Xero, Sage Intacct, and NetSuite are central to how coded transactions flow into the general ledger. Businesses with multiple departments or cost centers that need real-time budget visibility and configurable approval chains benefit from Ramp's role-based controls and reporting.$q$, $q$Finally, teams that want a single vendor for corporate cards, bill pay, procurement, and business travel rather than stitching together separate tools are natural candidates. Founders and controllers who value a modern, self-serve interface over long implementation cycles typically find the onboarding experience approachable compared with legacy expense and procurement software.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very early-stage or pre-revenue companies without an established U.S. business banking history may find card underwriting and credit limits more restrictive than expected, since card approval and limits are tied to the business's financial profile. Companies whose operations are heavily international, or that need extensive local-currency card issuance and multi-entity support outside Ramp's supported countries, may find coverage more limited than global-first competitors.$q$, $q$Organizations that primarily need invoicing and accounts receivable tools should also look elsewhere, since Ramp is focused on the spend and payables side of finance rather than billing customers or collecting revenue. Businesses that are satisfied with an existing, deeply customized combination of card, expense, and ERP tools may not see enough incremental benefit to justify a migration, particularly if they rely on integrations or workflows Ramp does not yet support.$q$, $q$Teams that want unlimited phone-based or highly white-glove support without moving to a paid plan may also be frustrated, since the richest support and account management experience is generally reserved for Plus and Enterprise customers. Companies uncomfortable with a card provider that earns revenue from interchange rather than subscription fees, or that require pricing structures entirely different from Ramp's free-plus-paid-tier model, should evaluate alternatives before committing.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Ramp provides corporate charge cards with configurable spend limits and controls, issued as unlimited physical and virtual cards without the fees typically associated with traditional business credit cards. Expense management is built around automatic receipt capture and matching, so employees can submit expenses through SMS, email, Slack, or the mobile app instead of manual expense reports.$q$, $q$The accounts payable and bill pay module uses optical character recognition to extract invoice data, route bills through configurable approval workflows, and schedule vendor payments, reducing manual data entry for finance teams. Accounting automation auto-codes transactions and syncs them to connected accounting or ERP platforms, while procurement tools add purchase-request workflows and vendor management for organizations on paid plans.$q$, $q$Ramp also includes integrated business travel booking for flights and hotels tied to company spend policy, a treasury offering for holding and moving business cash, real-time reporting and budget dashboards for cross-department visibility, and AI-driven capabilities the company markets under its Ramp Intelligence branding for tasks like anomaly detection and policy checks. Custom approval workflows and role-based permissions round out the platform's administrative controls.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('73bfc873-4265-4959-93b9-df520ad9fcd5', $q$the-ramp-experience$q$, $q$The Ramp Experience$q$, 2, ARRAY[$q$Day to day, Ramp is generally described as a modern, self-serve platform: signing up and issuing cards can happen quickly, and the web dashboard and mobile app share a consistent, relatively uncluttered design compared with older finance software. Admins can set spend policies, review transactions, and approve bills from either the browser or the mobile app, which also supports on-the-go reimbursement submission with receipt photos and mileage tracking.$q$, $q$For employees, the experience is centered on avoiding manual expense reports: card swipes trigger automatic prompts for receipts and memos through email, Slack, or text message, and most routine transactions require little additional effort once policies are configured. Approvals for cards, bills, reimbursements, and limit changes can be handled from a mobile inbox, which is useful for managers who need to respond quickly while away from a desk.$q$, $q$Support and account experience differs by plan: free-tier customers get self-serve resources and standard support channels, while Plus and Enterprise customers gain access to priority support and, at the top tier, dedicated account management and white-glove implementation help. Overall, the platform is positioned around reducing the operational overhead of running corporate cards, payables, and expense processes rather than being the cheapest raw card product on the market.$q$]::text[], 4);
