INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Customizable hiring pipelines$q$, $q$Build role-specific pipeline stages and move candidates through them with drag-and-drop cards, tags, and bulk actions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$CareersHub careers site$q$, $q$Publish a branded, multi-page careers site and job postings without needing separate web development work.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Multi-channel job distribution$q$, $q$Push open roles out to multiple job boards and channels from a single posting inside the platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Employee referrals (ReferralsHub)$q$, $q$Give internal staff a simple way to refer candidates for open roles and track referral activity.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$AI writing assistant$q$, $q$Draft and refine job descriptions and candidate communications with built-in AI writing support.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$AI screening and matching assistants$q$, $q$Use AI-driven screening and candidate matching to surface relevant applicants from the existing candidate database.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Interview scheduling$q$, $q$Coordinate interviews with hiring panels through calendar integrations that reduce manual back-and-forth.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Collaboration tools$q$, $q$Share candidate profiles, comment threads, and scorecards so hiring managers can weigh in without extra training.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Reporting and analytics$q$, $q$Track pipeline health and hiring metrics, with custom reporting available on higher-tier plans.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Single sign-on and integrations$q$, $q$Connect to broader HR and business intelligence tools and enable SSO on upper-tier plans for larger organizations.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Visual, collaborative pipeline makes it easy for hiring managers to participate without formal training$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Built-in careers site and multi-channel job posting reduce the need for extra tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$AI writing, screening, and matching features are built directly into upper plans$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Employee referrals and calendar-synced interview scheduling reduce manual coordination work$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Free trial available with no credit card required to explore the platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Pricing is no longer published and requires a sales conversation based on employee count$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Annual contracts appear to be the standard commitment, which limits short-term flexibility$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Advanced AI and compliance features are reserved for higher tiers, adding cost for smaller teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$May be more structure than very small companies with occasional hiring needs actually require$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Deep enterprise-grade compliance and multi-country configuration may be more limited than dedicated large-enterprise HR suites$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$What is Recruitee used for?$q$, $q$Recruitee is an applicant tracking system used to manage job postings, candidate pipelines, interview scheduling, and hiring collaboration for small and mid-sized companies.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Is Recruitee the same as Tellent?$q$, $q$Recruitee operates as Tellent Recruitee, a product within the Tellent group, which also owns other HR software products; the Recruitee ATS itself continues to operate under that branding.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Does Recruitee offer a free trial?$q$, $q$Yes, Recruitee offers a free trial that does not require a credit card, allowing teams to test the platform before committing to a paid plan.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$How is Recruitee priced?$q$, $q$Recruitee's plans are quoted based on the number of employees at your organization and your billing period, so exact pricing requires contacting sales rather than a published rate.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Does Recruitee include AI features?$q$, $q$Yes, Recruitee includes AI-assisted job description writing on its entry plan, with AI candidate screening and matching assistants available on higher-tier plans.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Replacing spreadsheet-based hiring$q$, $q$Move candidate tracking, interview notes, and hiring status out of shared spreadsheets and into a single collaborative pipeline.$q$, $q$Growing small businesses hiring their first dedicated recruiter or HR hire$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Building a self-serve careers site$q$, $q$Launch a branded careers page and distribute job postings across multiple channels without a separate web project.$q$, $q$Startups and SMBs without in-house web development resources$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Running multiple concurrent searches$q$, $q$Manage several open roles at once with per-role pipelines, tagging, and collaborator comments across hiring teams.$q$, $q$Recruiting agencies and internal talent teams handling multiple simultaneous roles$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Scaling employee referrals$q$, $q$Use the built-in referrals module to let employees submit candidates for open roles and track referral outcomes.$q$, $q$Mid-sized companies building an internal referral pipeline alongside external sourcing$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Start$q$, $q$Contact for pricing$q$, $q$Monthly or annual (annual discount available)$q$, $q$["Active job posts","Single-page CareersHub","Team collaboration and candidate management","AI writing assistant","Standard reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Advance$q$, $q$Contact for pricing$q$, $q$Monthly or annual (annual discount available)$q$, $q$["Unlimited job posts","Multi-page CareersHub","Employee referrals (ReferralsHub)","AI screening and matching assistants","Workflow automations","Advanced custom reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$Optimize$q$, $q$Contact for pricing$q$, $q$Monthly or annual (annual discount available)$q$, $q$["Single sign-on","Dedicated customer success manager","Expanded AI screening and matching","Requisition approval workflows","Unlimited custom fields","BI tool integrations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Recruitee, now operating under the Tellent group as Tellent Recruitee, is a cloud-based applicant tracking system built to help small and mid-sized businesses run their hiring process from one place. Founded in 2015 in Amsterdam, the Netherlands, it grew from an early-stage hiring tool into a broader recruitment platform aimed at teams that need structure and collaboration without the complexity of a full enterprise HR suite. Its Amsterdam roots are still reflected in the product, which leans toward European hiring norms and multilingual careers pages alongside its English-first interface.$q$, $q$The platform centers on a visual hiring pipeline where recruiters can move candidates through customizable stages, tag colleagues for feedback, and automate repetitive steps such as interview scheduling and follow-up emails. A branded careers page, called CareersHub, lets companies publish job openings and collect applications directly, without needing separate web development or a dedicated careers site build. Recruiters can also share individual candidate profiles internally with a link, which keeps hiring managers looped in without requiring every stakeholder to log into the full system.$q$, $q$Since becoming part of Tellent, Recruitee has added AI-assisted job writing, candidate screening, and matching tools on top of its existing collaboration and reporting features. This positions it as a middle-ground option between free spreadsheet-based hiring trackers and much larger, higher-cost enterprise talent acquisition platforms aimed at large HR departments. Tellent also sells complementary HR products alongside Recruitee, which gives existing customers a path to add broader people-management tools later without switching vendors entirely.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$who-recruitee-is-for$q$, $q$Who Recruitee Is For$q$, 2, ARRAY[$q$Recruitee is generally aimed at small and mid-sized companies that are hiring often enough to outgrow email threads and spreadsheets but do not have a dedicated recruiting operations team. Startups scaling headcount, agencies running multiple client searches, and growing HR teams building their first real hiring process are common fits for the platform.$q$, $q$Hiring managers who need visibility without living inside the tool also benefit, since Recruitee is built around shared pipelines, comment threads, and scorecards that let non-recruiters weigh in on candidates quickly. Companies that want a self-serve careers page and simple job board distribution without hiring a developer tend to find the setup approachable.$q$, $q$Teams already committed to Slack, common calendar tools, and standard job boards will likely get the most value, since Recruitee's integrations and workflow automations are built around those everyday tools rather than niche or highly specialized recruiting stacks. Companies running employee referral programs may also appreciate the built-in referrals module, which gives internal staff a simple way to submit candidates without a separate system.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very large enterprises with complex, multi-country compliance needs, deep HRIS integration requirements, or highly customized approval chains may find Recruitee's structure more limiting than a large enterprise-grade suite designed specifically for that scale. Organizations that need extensive configurability across many business units should evaluate whether Recruitee's tiers cover their governance needs.$q$, $q$Companies that hire only occasionally, such as very small businesses making one or two hires a year, may find a paid ATS unnecessary and could be better served by free or lower-cost alternatives until hiring volume grows enough to justify a dedicated tool.$q$, $q$Teams that need pricing certainty upfront may also want to look elsewhere first, since Recruitee's current plans are quoted based on employee count and billing period rather than published flat rates, which means budgeting requires a sales conversation rather than a simple self-serve signup.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Recruitee provides a customizable hiring pipeline, candidate database, and collaborative hiring tools that let recruiters and hiring managers work from a shared view of every open role. Pipelines can be tailored per role, and bulk actions help manage high volumes of applicants without manual repetition.$q$, $q$The CareersHub careers site and job board distribution tools let companies publish openings across multiple channels from a single posting, while an employee referrals module helps surface internal candidate leads. Interview scheduling tools sync with common calendar systems to reduce the back-and-forth of coordinating hiring panels.$q$, $q$AI-assisted features, including a writing assistant for job descriptions and screening and matching assistants for surfacing relevant candidates from an existing database, are layered onto the higher plans. Reporting and analytics tools track pipeline health and hiring metrics, with more advanced custom reporting available on upper tiers alongside integrations, single sign-on, and requisition approval workflows for larger teams. A browser extension is also available for sourcing candidate details directly from professional networking sites into the pipeline.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', $q$the-recruitee-experience$q$, $q$The Recruitee Experience$q$, 2, ARRAY[$q$Using Recruitee day to day generally starts with setting up a careers site and job templates, then building out pipeline stages that match how a company actually interviews. Because the interface is built around drag-and-drop candidate cards and shared comment threads, most hiring managers can be onboarded with a short walkthrough rather than formal training.$q$, $q$Recruiters tend to spend their time inside candidate profiles and pipeline views, using tags, scorecards, and automated emails to keep processes moving without manually re-entering information. The mobile-friendly interface and browser extension for sourcing candidates from professional networks are frequently mentioned as conveniences that reduce manual data entry.$q$, $q$Overall, the experience is closer to a modern collaboration tool than a legacy enterprise system, which is consistent with Recruitee's original positioning for growing teams. Companies moving up from spreadsheets often describe the transition as straightforward, while teams with more complex compliance or approval needs may need to lean on the higher tiers or support resources to configure the platform to fit their process. Because pricing now requires a sales conversation rather than a self-serve checkout, prospective customers should expect an onboarding call before they can compare exact costs across tiers.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6b1fba57-cd15-424e-804c-46b51d8f4396', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
