INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Subscription plan management$q$, $q$Configure flexible subscription plans, free trials, coupons, and promotions, with automatic proration for upgrades and downgrades.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Automated dunning and churn recovery$q$, $q$Recover failed payments with automated retry logic and multiple configurable dunning campaigns.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$AI-assisted churn prediction$q$, $q$Higher tiers include a propensity-to-churn model that flags at-risk subscribers so teams can offer targeted retention incentives.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Multi-gateway payment orchestration$q$, $q$Connect to a broad range of payment gateways and support 10+ payment methods for global billing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Multicurrency and global billing support$q$, $q$Bill subscribers in multiple currencies and support region-specific payment preferences.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Revenue recognition (RevRec)$q$, $q$An add-on product that automates contract modifications, rules-driven revenue allocation, and multi-GAAP compliant revenue recognition with an audit trail.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Hosted subscriber management portal$q$, $q$Give subscribers a self-serve portal to manage their own billing details, plans, and cancellations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$REST API and client libraries$q$, $q$Build custom billing workflows using Recurly's API, with official client libraries for several popular programming languages.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Custom reporting and analytics$q$, $q$Access reporting on subscription metrics such as billing volume, recovered revenue, and churn.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Shopify subscription commerce integration$q$, $q$A dedicated All-Access for Shopify bundle supports bundles, prepaid and gift subscriptions, and self-serve subscription management for Shopify stores.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Purpose-built for recurring and subscription billing with deep dunning and churn-recovery tooling$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Broad payment gateway and payment method coverage for global billing operations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Optional RevRec add-on handles complex, multi-GAAP revenue recognition$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Official API client libraries across several popular programming languages$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Established vendor with a long track record in the subscription billing space since 2009$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Pricing beyond the Starter plan is quoted individually rather than published, requiring a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Percentage-of-billing-volume pricing can become expensive as revenue scales$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$The All-Access tier requires a $1 million+ annual billing volume minimum, out of reach for small businesses$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$AI-assisted churn prediction and other advanced features are gated behind higher tiers or add-ons$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Less suited to businesses needing highly granular usage-based metering as their primary billing model$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Does Recurly offer a free trial?$q$, $q$Yes, the Starter plan includes a 90-day free trial before billing begins.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$How does Recurly's pricing work?$q$, $q$The Starter plan combines a flat monthly fee with a percentage of billing volume, while higher tiers such as All-Access are quoted individually based on billing volume and contract terms.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$What payment gateways and methods does Recurly support?$q$, $q$Recurly connects to a large number of payment gateways and supports 10+ payment methods, expanding to additional methods like ACH on higher tiers.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Does Recurly integrate with Shopify?$q$, $q$Yes, Recurly offers an All-Access for Shopify bundle tailored to Shopify-based subscription commerce.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$What is RevRec?$q$, $q$RevRec is Recurly's revenue recognition add-on that automates contract modifications and rules-driven revenue allocation to help finance teams stay compliant with multi-GAAP standards.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$SaaS subscription billing$q$, $q$Automate recurring plan billing, trials, upgrades, and downgrades for a software-as-a-service product.$q$, $q$SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Direct-to-consumer subscription commerce$q$, $q$Run subscription boxes, replenishment programs, or bundles on Shopify with prepaid and gift subscription support.$q$, $q$DTC and ecommerce subscription brands$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Churn prevention and recovery campaigns$q$, $q$Use dunning campaigns and AI-assisted churn prediction to recover failed payments and retain at-risk subscribers.$q$, $q$Growth and retention teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Revenue recognition and compliance$q$, $q$Automate contract-driven revenue allocation and maintain an audit trail for multi-GAAP compliance.$q$, $q$Finance and accounting teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Starter$q$, $q$$249/month + 0.9% of billing volume$q$, $q$Monthly$q$, $q$["Automated global subscription billing","Flexible plans and pricing","Static churn-prevention tools","1 dunning campaign","10+ payment methods","20+ payment gateways","90-day free trial"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$All-Access$q$, $q$Custom, starting under 1% of billing volume (requires $1M+ annual billing volume)$q$, $q$Annual$q$, $q$["Everything in Starter","AI-powered churn prediction and analytics","Multiple dunning campaigns","Advanced plans, pricing, and promotions","Payments orchestration","Custom reporting","Multicurrency support","Single sign-on"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$Enterprise / Add-ons (Engage, RevRec)$q$, $q$Custom pricing$q$, $q$Annual$q$, $q$["Personalized churn-prevention offers via Engage","A/B testing and subscriber segmentation","Automated revenue recognition via RevRec","Multi-GAAP compliance and audit trail","Dedicated account support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Recurly is a subscription billing and revenue management platform founded in 2009 and headquartered in San Francisco, California. It was built specifically for companies whose revenue model depends on recurring billing rather than one-time transactions, and it has grown into one of the more established names in the subscription commerce space alongside competitors such as Chargebee and Zuora.$q$, $q$At its core, Recurly automates the mechanics of recurring billing: creating and managing subscription plans, calculating prorations for upgrades and downgrades, retrying failed payments through dunning management, and reconciling revenue across many payment gateways and methods. Beyond core billing, Recurly has expanded into adjacent products it markets separately - Engage for churn prevention and customer engagement, and RevRec for automated revenue recognition under multi-GAAP accounting rules.$q$, $q$Recurly positions itself less as a simple payment processor and more as end-to-end subscription infrastructure, offering its own APIs and client libraries for developers who want to build custom billing logic on top of the platform, alongside a hosted subscriber portal for teams that prefer configuration over code. Pricing is largely tied to the billing volume a business processes rather than flat per-seat fees, a structural difference worth understanding before evaluating the platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$who-recurly-is-for$q$, $q$Who Recurly Is For$q$, 2, ARRAY[$q$Recurly is aimed at subscription-based businesses - SaaS companies, streaming and media services, subscription boxes, and membership sites - that have moved past relying on a payment processor's native billing tools and need dedicated recurring-billing infrastructure. Its entry-level Starter plan, which includes a 90-day free trial, is built for smaller businesses processing roughly under $40,000 in monthly billings.$q$, $q$The platform's more advanced All-Access tier requires at least $1 million in annual billing volume, signaling that Recurly's deeper feature set - AI-assisted churn prevention, multicurrency support, payments orchestration across many gateways, and single sign-on - is really designed for growth-stage and mid-market subscription companies rather than early-stage startups.$q$, $q$Recurly also offers a dedicated bundle for Shopify-based subscription commerce, making it a reasonable fit for direct-to-consumer subscription-box or replenishment brands selling through Shopify. Finance and revenue teams at companies with complex, contract-driven revenue recognition needs may also consider Recurly specifically for its RevRec add-on rather than the billing core alone.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small or pre-revenue businesses that only need to charge a handful of customers a flat recurring fee are usually better served by a payment processor's built-in subscription tools or a lighter-weight billing product, since Recurly's percentage-of-volume pricing and setup overhead are hard to justify at very low billing volume.$q$, $q$Companies that need highly bespoke, non-standard billing logic - complex hybrid usage metering, for instance - may find that some competitors emphasize flexible metered billing more directly, and should compare specifically on that dimension before committing, since Recurly's core strength has traditionally been subscription and plan-based billing rather than granular usage metering.$q$, $q$Businesses that want fully transparent, self-serve pricing without a sales conversation may be frustrated by Recurly, since most tiers beyond Starter are quoted individually and require a minimum billing volume commitment; teams that prioritize pricing transparency over feature depth may prefer a vendor that publishes flat, non-negotiated tiers.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Recurly's core billing engine covers the standard recurring-revenue workflow: configurable subscription plans, trials, coupons and promotions, prorated upgrades and downgrades, and support for many payment methods across a large number of payment gateways, reducing the need to stitch together separate tools for each region or payment type.$q$, $q$Dunning and churn-recovery tooling is a central selling point - Recurly runs automated retry logic and multiple configurable dunning campaigns to recover failed payments, and its higher tiers layer on AI-assisted, predictive churn models that estimate which subscribers are at risk of canceling so a team can intervene with targeted offers.$q$, $q$For finance-heavy use cases, the RevRec add-on automates contract modifications, rules-driven revenue allocation, and multi-GAAP compliant revenue recognition with an audit trail, while the core platform also offers a hosted subscriber management portal, custom reporting, and REST APIs with official client libraries for languages including Ruby, Python, Node.js, Java, PHP, and .NET.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2899eedd-31f8-47bb-91c7-6b9e3cb0215b', $q$the-recurly-experience$q$, $q$The Recurly Experience$q$, 2, ARRAY[$q$Setting up Recurly typically starts with defining subscription plans and connecting one or more payment gateways; the dashboard centers on subscriber accounts, invoices, and billing events, and most day-to-day billing operations - issuing credits, pausing a subscription, updating a payment method - can be handled without engineering involvement once initial configuration is in place.$q$, $q$Developers who need custom checkout flows, usage-based add-ons, or integrations with a broader billing stack rely on Recurly's REST API and webhooks, and the platform documents its client libraries and API versioning, including a defined support policy for older API versions, reasonably thoroughly for teams building on top of it.$q$, $q$Because pricing and onboarding for anything beyond the Starter plan tend to involve a sales conversation, the buying experience feels closer to enterprise software procurement than a self-serve SaaS signup - something to budget time for when evaluating Recurly against tools with instant self-serve pricing.$q$]::text[], 4);
